import{_ as s,o as n,c as e,S as p}from"./chunks/framework.C6RQlTYc.js";const m=JSON.parse('{"title":"面试官问：大模型\\"幻觉\\"是什么？前端如何缓解？","description":"","frontmatter":{},"headers":[],"relativePath":"面试官问/17ai/q_ai_12-hallucination.md","filePath":"面试官问/17ai/q_ai_12-hallucination.md","lastUpdated":1778207238000}'),l={name:"面试官问/17ai/q_ai_12-hallucination.md"};function i(t,a,r,o,c,u){return n(),e("div",null,[...a[0]||(a[0]=[p(`<h1 id="面试官问-大模型-幻觉-是什么-前端如何缓解" tabindex="-1">面试官问：大模型&quot;幻觉&quot;是什么？前端如何缓解？ <a class="header-anchor" href="#面试官问-大模型-幻觉-是什么-前端如何缓解" aria-label="Permalink to &quot;面试官问：大模型&quot;幻觉&quot;是什么？前端如何缓解？&quot;">​</a></h1><blockquote><p>📚 参考：<a href="/FE-prepare-interview/直击概念/17ai/s_ai_20-hallucination.html">模型幻觉</a> | <a href="/FE-prepare-interview/直击概念/17ai/s_ai_23-rag.html">RAG 检索增强生成</a></p></blockquote><p><strong>场景</strong>：面试官问&quot;我们用 AI 做客服，它经常编造答案怎么办？前端能做哪些缓解？&quot;</p><p><strong>考察点</strong>：幻觉类型和根因、前端缓解手段、RAG 原理</p><details class="details custom-block"><summary>详细信息</summary><h2 id="核心回答" tabindex="-1">核心回答 <a class="header-anchor" href="#核心回答" aria-label="Permalink to &quot;核心回答&quot;">​</a></h2><p><strong>模型幻觉</strong>（Hallucination）指模型生成的内容与事实不符，却表现出&quot;一本正经胡说八道&quot;。</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0"><code><span class="line"><span>幻觉类型：</span></span>
<span class="line"><span>├── 事实性幻觉：编造不存在的人物/事件/数据</span></span>
<span class="line"><span>│   例：&quot;李白写过一首《咏鹅》&quot; ❌ — 这是骆宾王写的</span></span>
<span class="line"><span>├── 忠实性幻觉：偏离用户指令或上下文</span></span>
<span class="line"><span>│   例：用户问&quot;A方案&quot;，模型在回答里混入了 B 方案的细节</span></span>
<span class="line"><span>└── 逻辑性幻觉：推理链条断裂，前后矛盾</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p><strong>幻觉的根因</strong>：</p><ul><li>本质是 next token prediction，不存在&quot;事实检查&quot;机制</li><li>训练数据包含错误信息</li><li>解码时采样随机性（temperature 高时更容易胡说）</li></ul><p><strong>前端缓解手段</strong>：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────────┐</span></span>
<span class="line"><span>│ 1. RAG（检索增强生成）                    │</span></span>
<span class="line"><span>│    查询知识库 → 找到相关文档 → 塞进 prompt   │</span></span>
<span class="line"><span>│    &quot;根据以下资料回答问题：{检索到的文档}&quot;    │</span></span>
<span class="line"><span>│    效果：把模型从&quot;凭记忆回答&quot;变成&quot;开卷考试&quot; │</span></span>
<span class="line"><span>├─────────────────────────────────────────┤</span></span>
<span class="line"><span>│ 2. 提示词约束                            │</span></span>
<span class="line"><span>│    &quot;如果不知道答案，直接说不知道，不要编造&quot;  │</span></span>
<span class="line"><span>│    &quot;请引用原文来证明你的回答&quot;               │</span></span>
<span class="line"><span>├─────────────────────────────────────────┤</span></span>
<span class="line"><span>│ 3. 温度控制                              │</span></span>
<span class="line"><span>│    temperature=0 时输出最确定（极少胡说）    │</span></span>
<span class="line"><span>│    temperature=0.7~1.0 时更有创造性但更易编造│</span></span>
<span class="line"><span>├─────────────────────────────────────────┤</span></span>
<span class="line"><span>│ 4. 校验层                                │</span></span>
<span class="line"><span>│    输出后调置信度检测 API                   │</span></span>
<span class="line"><span>│    或用更强的模型做事后审核                 │</span></span>
<span class="line"><span>└─────────────────────────────────────────┘</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br></div></div><h2 id="面试回答要点" tabindex="-1">面试回答要点 <a class="header-anchor" href="#面试回答要点" aria-label="Permalink to &quot;面试回答要点&quot;">​</a></h2><ul><li>能用&quot;开卷考试&quot;比喻解释 RAG 为什么能减少幻觉</li><li>说出至少 2 种前端可操作的缓解手段</li><li>知道 temperature 越低越确定性</li></ul></details><blockquote><p>来源：<a href="/FE-prepare-interview/直击概念/17ai/s_ai_20-hallucination.html">模型幻觉概念讲解</a></p></blockquote>`,6)])])}const d=s(l,[["render",i]]);export{m as __pageData,d as default};
